async processAppointment(job: Job) {
  const lockKey = `lock:appt:${job.data.appointmentRef}`;
  const lock = await redis.set(lockKey, '1', { NX: true, PX: 30000 });
  if (!lock) {
    logger.warn('Duplicate job skipped', { ref: job.data.appointmentRef });
    return { skipped: true, reason: 'lock_held' };
  }
  try {
    const result = await AppointmentService.create(job.data);
    return result;
  } finally {
    await redis.del(lockKey); // always release
  }
}

hints.text:
The Redis client is already available via the REDIS_URL env var. Import ioredis and create a client:
import Redis from 'ioredis';
const redisClient = new Redis(process.env.REDIS_URL);

📋 EXPERT SAMPLE (lock structure only):

const lockKey = `lock:booking:${job.data.bookingRef}`;
const lock = await redisClient.set(lockKey, 'locked', { NX: true, PX: 30000 });
if (!lock) return { skipped: true };
try { const result = await processBooking(job.data); return result; }
finally { await redisClient.del(lockKey); }

NX: true means 'set only if Not eXists' — this is what prevents two workers from both acquiring the lock simultaneously. PX: 30000 is the TTL in milliseconds (30 seconds) — prevents deadlock if the worker crashes.

📋 EXPERT SAMPLE (full lock with error handling):

async processBooking(job: Job<BookingJobData>) {
  const lockKey = `lock:booking:${job.data.bookingRef}`;
  const locked = await redisClient.set(lockKey,'locked',{NX:true,PX:30000});
  if (!locked) {
    logger.warn('Duplicate job skipped', {ref: job.data.bookingRef});
    throw new Error('DUPLICATE_JOB'); // BullMQ will move to failed
  }
  try {
    return await BookingService.create(job.data);
  } finally {
    await redisClient.del(lockKey);
  }
}

